#include <bits/stdc++.h>
#define rep(i, n) for (int i = 0; i < n; i++)
#define PI pair<int, int>
#define all(v) v.begin(), v.end()
#define ll long long

template <class T, class U>
inline bool chmin(T &a, U b) {
    if (a > b) {
        a = b;
        return true;
    }
    return false;
}
template <class T, class U>
inline bool chmax(T &a, U b) {
    if (a < b) {
        a = b;
        return true;
    }
    return false;
}
