struct UnionFind {
    int N;
    vector<int> par, siz;
    int find(int x) { return (par[x] == x ? x : par[x] = find(par[x])); }
    void merge(int x, int y) {
        x = find(x), y = find(y);
        if (x == y) return;
        if (siz[x] > siz[y]) swap(x, y);
        par[x] = y;
        siz[y] += siz[x];
    }
    UnionFind(int N) : N(N), siz(N, 1), par(N) {
        iota(par.begin(), par.end(), 0);
    }
};

int dx[] = {-1, 0, 1, 0}, dy[] = {0, 1, 0, -1};

ofstream ofs("./b.txt");
struct Act {
    int type, x, y;
};
struct Game {
    vector<vector<bool>> C;
    vector<vector<bool>> wall_hrz, wall_vert;
    vector<int> X, Y, wall_used, score;
    bool is_finished = false;

    int MAX_WALL = 10;
    int turn = 0;
    vector<Act> acts;

    bool isConnected() {
        UnionFind uf(81);
        rep(i, 9) rep(j, 9) {
            if (i < 8 && !wall_hrz[i][j]) uf.merge(i * 9 + j, (i + 1) * 9 + j);
            if (j < 8 && !wall_vert[i][j]) uf.merge(i * 9 + j, i * 9 + j + 1);
        }
        return uf.siz[uf.find(0)] == 81;
    }

    bool isOK(Act act) {
        if (act.type == 0) {
            if (act.x == 0)
                return X[turn] && !wall_hrz[X[turn] - 1][Y[turn]];
            else if (act.x == 1)
                return Y[turn] != 8 && !wall_vert[X[turn]][Y[turn]];
            else if (act.x == 2)
                return X[turn] != 8 && !wall_hrz[X[turn]][Y[turn]];
            else if (act.x == 3)
                return Y[turn] && !wall_vert[X[turn]][Y[turn] - 1];
            else
                return false;
        } else if (act.type == 1) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL) return false;
            if (wall_hrz[act.x][act.y] || wall_hrz[act.x][act.y + 1])
                return false;
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            bool res = isConnected();
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = false;
            return res;
        } else if (act.type == 2) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL) return false;
            if (wall_vert[act.x][act.y] || wall_vert[act.x + 1][act.y])
                return false;
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            bool res = isConnected();
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = false;
            return res;
        } else
            return false;
    }

    vector<Act> candidateActs() {
        vector<Act> res;
        rep(i, 4) {
            if (isOK(Act{0, i, 0})) res.push_back(Act{0, i, 0});
        }
        rep(i, 9) rep(j, 9) {
            if (isOK(Act{1, i, j})) res.push_back(Act{1, i, j});
            if (isOK(Act{2, i, j})) res.push_back(Act{2, i, j});
        }
        return res;
    }

    bool applyAct(Act act, bool check = true) {
        if (check && !isOK(act)) return false;
        if (act.type == 0) {
            X[turn] += dx[act.x];
            Y[turn] += dy[act.x];
            if (C[X[turn]][Y[turn]]) {
                score[turn]++;
                C[X[turn]][Y[turn]] = false;
            }
        } else if (act.type == 1) {
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            wall_used[turn]++;
        } else {
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            wall_used[turn]++;
        }
        bool flag = false;
        rep(i, 9) rep(j, 9) {
            if (C[i][j]) flag = true;
        }
        if (!flag) is_finished = true;
        acts.push_back(act);
        turn ^= 1;
        return true;
    }

    void printBoard() {
        cout << "Score: " << score[0] << " " << score[1] << "\n"
             << "Wall counter: " << wall_used[0] << " " << wall_used[1] << endl
             << endl;
        rep(i, 9) {
            rep(j, 9) {
                if (i == X[0] && j == Y[0] && i == X[1] && j == Y[1])
                    cout << " AB";
                else if (i == X[0] && j == Y[0])
                    cout << " A ";
                else if (i == X[1] && j == Y[1])
                    cout << " B ";
                else {
                    if (C[i][j])
                        cout << " # ";
                    else
                        cout << " . ";
                }
                if (j < 8) cout << (wall_vert[i][j] ? " | " : "   ");
            }
            cout << endl;
            if (i != 8) {
                rep(j, 9) {
                    if (j) cout << "   ";
                    cout << (wall_hrz[i][j] ? "---" : "   ");
                }
            }
            cout << endl;
        }
        cout << endl;
    }

    void bfs(int sx, int sy, int dis[9][9]) {
        rep(i, 9) rep(j, 9) dis[i][j] = -1;
        dis[sx][sy] = 0;
        queue<PI> que;
        que.push({sx, sy});
        while (que.size()) {
            PI p = que.front();
            que.pop();
            int x = p.first, y = p.second;
            auto upd = [&](int nx, int ny) {
                if (dis[nx][ny] == -1) {
                    dis[nx][ny] = dis[x][y] + 1;
                    que.push({nx, ny});
                }
            };
            if (x && !wall_hrz[x - 1][y]) upd(x - 1, y);
            if (y != 8 && !wall_vert[x][y]) upd(x, y + 1);
            if (x != 8 && !wall_hrz[x][y]) upd(x + 1, y);
            if (y && !wall_vert[x][y - 1]) upd(x, y - 1);
        }
    }
    int tsp(int t) {
        vector<vector<bool>> D = C;
        int dis[9][9];
        memset(dis, -1, sizeof(dis));
        int stx = X[t], sty = Y[t];
        int res = 0;
        rep(_, 3) {
            queue<PI> que;
            que.push({stx, sty});
            dis[stx][sty] = 0;
            vector<PI> v;
            v.push_back({stx, sty});
            int tx = -1, ty = -1;
            while (que.size()) {
                PI p = que.front();
                que.pop();
                int x = p.first, y = p.second;
                if (D[x][y]) {
                    tx = x, ty = y;
                    D[x][y] = false;
                    break;
                }
                auto upd = [&](int nx, int ny) {
                    if (dis[nx][ny] == -1) {
                        dis[nx][ny] = dis[x][y] + 1;
                        v.push_back({nx, ny});
                        que.push({nx, ny});
                    }
                };
                if (x && !wall_hrz[x - 1][y]) upd(x - 1, y);
                if (y != 8 && !wall_vert[x][y]) upd(x, y + 1);
                if (x != 8 && !wall_hrz[x][y]) upd(x + 1, y);
                if (y && !wall_vert[x][y - 1]) upd(x, y - 1);
            }
            if (tx == -1) return res;
            res += dis[tx][ty];
            stx = tx, sty = ty;
            for (PI i : v) {
                dis[i.first][i.second] = -1;
            }
        }
        return res;
    }
    double evaluate() {
        double sc[2];
        rep(i, 2) sc[i] = (double)score[i] - (double)tsp(i) / 10.;
        return sc[0] - sc[1];
    }
    Game()
        : C(9, vector<bool>(9)),
          wall_hrz(9, vector<bool>(9)),
          wall_vert(9, vector<bool>(9)),
          X(2),
          Y(2),
          wall_used(2),
          score(2) {
        wall_used[0] = wall_used[1] = 0;
        score[0] = score[1] = 0;
        X[0] = 8, X[1] = 0, Y[0] = Y[1] = 4;
    }
};

pair<double, Act> alphabeta(Game game, int max_depth, int current_depth,
                            double alpha, double beta) {
    int turn = game.turn;
    if (current_depth == max_depth) {
        return {game.evaluate(), Act{-1, -1, -1}};
    }
    if (game.is_finished) {
        if (game.score[0] > game.score[1]) {
            return {1e9, Act{-1, -1, -1}};
        } else if (game.score[0] == game.score[1]) {
            return {0, Act{-1, -1, -1}};
        } else {
            return {-1e9, Act{-1, -1, -1}};
        }
    }

    vector<Act> acts;
    rep(i, 4) {
        if (game.isOK(Act{0, i, 0})) acts.push_back(Act{0, i, 0});
    }
    if (current_depth < 6) {
        rep(x, 8) rep(y, 8) {
            bool flag1 = false, flag2 = false;
            rep(i, 2) {
                flag1 |= (game.X[i] - 2 <= x && x <= game.X[i] + 1 &&
                          game.Y[i] - 1 <= y && y <= game.Y[i]);
                flag2 |= (game.Y[i] - 2 <= y && y <= game.Y[i] + 1 &&
                          game.X[i] - 1 <= x && x <= game.X[i]);
            }

            flag1 |= (y && game.wall_hrz[x][y - 1]);
            flag1 |= (y && game.wall_vert[x][y - 1]);
            flag1 |= game.wall_vert[x][y];
            flag1 |= (y != 8 && game.wall_hrz[x][y + 1]);
            flag1 |= (x != 8 && y && game.wall_vert[x + 1][y - 1]);
            flag1 |= (x != 8 && game.wall_vert[x + 1][y]);

            flag2 |= (x && game.wall_hrz[x - 1][y]);
            flag2 |= (x && game.wall_vert[x - 1][y]);
            flag2 |= (x && y != 8 && game.wall_hrz[x - 1][y + 1]);
            flag2 |= game.wall_hrz[x][y];
            flag2 |= (y != 8 && game.wall_hrz[x][y + 1]);
            flag2 |= (x != 8 && game.wall_vert[x + 1][y]);
            if (flag1 && game.isOK(Act{1, x, y})) acts.push_back(Act{1, x, y});
            if (flag2 && game.isOK(Act{2, x, y})) acts.push_back(Act{2, x, y});
        }
    }
    Act best_act = {3, 0, 0};
    for (Act act : acts) {
        Game new_game = game;
        new_game.applyAct(act, false);
        pair<double, Act> res =
            alphabeta(new_game, max_depth, current_depth + 1, alpha, beta);
        if (turn == 0) {
            if (chmax(alpha, res.first)) best_act = act;
        } else {
            if (chmin(beta, res.first)) best_act = act;
        }
        if (alpha >= beta) break;
    }
    if (turn == 0) {
        return {alpha, best_act};
    } else {
        return {beta, best_act};
    }
}
Act choose(Game game) {
    pair<double, Act> res = alphabeta(game, 5, 0, -2e9, 2e9);
    // cout << counter << endl;
    // cout << eval_memo.size() << endl;
    return res.second;
}
